  const availableCount = UNITS.filter((u) => u.status === "available").length;

  // Mortgage math
  const loanAmount = Math.round(price * (1 - depositPct / 100));
  const monthlyRate = rate / 100 / 12;
  const n = term * 12;
  const monthly = monthlyRate > 0
    ? Math.round((loanAmount * monthlyRate * Math.pow(1 + monthlyRate, n)) / (Math.pow(1 + monthlyRate, n) - 1))
    : Math.round(loanAmount / n);

  const fx = { EUR: 1, USD: 1.08, GBP: 0.85, RUB: 98, CNY: 7.8, ILS: 3.95 };
  const fxSym = { EUR: "€", USD: "$", GBP: "£", RUB: "₽", CNY: "¥", ILS: "₪" };
